// 1. Configurações de data e nomes dos meses
const agora = new Date();
const umMesAtras = new Date();
umMesAtras.setMonth(agora.getMonth() - 1);

const meses = [
  "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
  "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
];
const nomeMesRelatorio = meses[umMesAtras.getMonth()];

// Função para formatar minutos em Dias, Horas e Minutos
const formatarTempoDinamico = (minutosTotal) => {
  if (minutosTotal === 0) return "0 min";

  const dias = Math.floor(minutosTotal / 1440);
  const horas = Math.floor((minutosTotal % 1440) / 60);
  const minutos = minutosTotal % 60;

  let resultado = "";
  if (dias > 0) resultado += `${dias}d `;
  if (horas > 0) resultado += `${horas}h `;
  if (minutos > 0 || resultado === "") resultado += `${minutos}min`;

  return resultado.trim();
};

// 2. Processamento de dados
const items = $input.all().map(i => i.json);
let stats = {};

items.forEach(item => {
  const startTime = new Date(item.start_time);
  const duracao = item.duration_minutes || 0;

  // Filtro atualizado para considerar apenas quedas maiores que 5 minutos
  if (startTime >= umMesAtras && duracao > 5) {
    const name = item.device_name || "Dispositivo Desconhecido";

    if (!stats[name]) {
      stats[name] = { quedas: 0, tempoTotal: 0 };
    }

    stats[name].quedas += 1;
    stats[name].tempoTotal += duracao;
  }
});

const ranking = Object.entries(stats).map(([name, data]) => ({
  name,
  ...data
}));

// Cálculos para os cards
const totalTempoOffGlobal = ranking.reduce((acc, curr) => acc + curr.tempoTotal, 0);
const recordistaQuedas = [...ranking].sort((a, b) => b.quedas - a.quedas)[0] || { name: "N/A", quedas: 0 };
const maisTempoOff = [...ranking].sort((a, b) => b.tempoTotal - a.tempoTotal)[0] || { name: "N/A", tempoTotal: 0 };

// 3. Geração das linhas da tabela
const rowsHtml = ranking
  .sort((a, b) => b.tempoTotal - a.tempoTotal)
  .map((dev) => {
    return `
    <tr style="border-bottom: 1px solid #333;">
      <td style="padding: 12px 0; font-size: 14px; color: #ddd;">${dev.name}</td>
      <td style="padding: 12px 0; text-align: center; color: #ddd;">${dev.quedas}</td>
      <td style="padding: 12px 0; text-align: right; color: #e76e55; font-weight: bold;">${formatarTempoDinamico(dev.tempoTotal)}</td>
    </tr>
  `}).join('');

// 4. Template HTML Final
const htmlBody = `
<div style="background-color: #1e1e1e; color: #ffffff; font-family: 'Segoe UI', Helvetica, Arial, sans-serif; max-width: 600px; margin: auto; border-radius: 8px; overflow: hidden; border: 1px solid #333;">

  <div style="background-color: #0056b3; padding: 30px 20px; text-align: center;">
    <h2 style="margin: 0; font-size: 20px; font-weight: bold; letter-spacing: 0.5px; text-transform: uppercase;">Relatório Mensal Ubiquiti</h2>
    <div style="font-size: 14px; opacity: 0.9; margin-top: 5px;">${nomeMesRelatorio} de ${umMesAtras.getFullYear()}</div>
  </div>

  <div style="padding: 25px 20px;">

    <div style="display: table; width: 100%; border-spacing: 8px; border-collapse: separate; margin-left: -8px; margin-right: -8px; margin-bottom: 20px;">

      <div style="display: table-cell; width: 33%; border: 1px solid #444; border-radius: 8px; padding: 15px; text-align: center; background: #262626; vertical-align: middle;">
        <div style="font-size: 10px; color: #999; text-transform: uppercase; margin-bottom: 8px; font-weight: bold;">Tempo Total Off</div>
        <div style="font-size: 16px; font-weight: bold; color: #eee;">${formatarTempoDinamico(totalTempoOffGlobal)}</div>
      </div>

      <div style="display: table-cell; width: 33%; border: 1px solid #633333; border-radius: 8px; padding: 15px; text-align: center; background: #332424; vertical-align: middle;">
        <div style="font-size: 9px; color: #e76e55; text-transform: uppercase; margin-bottom: 5px; font-weight: bold;">Mais Quedas</div>
        <div style="font-size: 12px; font-weight: bold; color: #e76e55; line-height: 1.2; margin-bottom: 3px;">${recordistaQuedas.name}</div>
        <div style="font-size: 11px; color: #e76e55;">(${recordistaQuedas.quedas}x)</div>
      </div>

      <div style="display: table-cell; width: 33%; border: 1px solid #633333; border-radius: 8px; padding: 15px; text-align: center; background: #332424; vertical-align: middle;">
        <div style="font-size: 9px; color: #e76e55; text-transform: uppercase; margin-bottom: 5px; font-weight: bold;">Maior Tempo Off</div>
        <div style="font-size: 12px; font-weight: bold; color: #e76e55; line-height: 1.2; margin-bottom: 3px;">${maisTempoOff.name}</div>
        <div style="font-size: 11px; color: #e76e55;">(${formatarTempoDinamico(maisTempoOff.tempoTotal)})</div>
      </div>

    </div>

    <h3 style="font-size: 16px; border-bottom: 2px solid #0056b3; padding-bottom: 10px; margin-bottom: 15px; font-weight: bold;">Detalhamento por Dispositivo</h3>
    <table style="width: 100%; border-collapse: collapse;">
      <thead>
        <tr style="color: #777; font-size: 12px; text-transform: uppercase;">
          <th style="text-align: left; padding-bottom: 12px; font-weight: bold;">Dispositivo</th>
          <th style="text-align: center; padding-bottom: 12px; font-weight: bold;">Quedas</th>
          <th style="text-align: right; padding-bottom: 12px; font-weight: bold;">Tempo Off</th>
        </tr>
      </thead>
      <tbody>
        ${rowsHtml}
      </tbody>
    </table>

  </div>

  <div style="background-color: #0056b3; padding: 20px; text-align: center;">
    <img src="https://i.imgur.com/t0K9ER0.png" style="max-width: 150px; height: auto; display: block; margin: 0 auto;" alt="Logo Rodapé" />
  </div>

</div>
`;

return {
  email_subject: `Relatório Mensal Ubiquiti - ${nomeMesRelatorio}`,
  html_relatorio: htmlBody
};
